module fsm(
    input IN,
    input CLK,
    input RST,
    output reg MATCH
);

always @(posedge CLK or posedge RST) begin
    if (RST) begin
        MATCH <= 1'b0;
    end else begin
        case ({IN, MATCH})
            {1'b1, 1'b0}: MATCH <= 1'b1;
            {1'b0, 1'b1}, {1'b0, 1'b0}, {1'b1, 1'b1}, {1'b1, 1'b0}: MATCH <= 1'b0;
            default: MATCH <= 1'b0;
    endcase
end

